const output = $('Claude Bridge').item.json.output;
const elapsed = $('Claude Bridge').item.json.elapsed_s;
const now = new Date();
const date = `${String(now.getDate()).padStart(2,'0')}/${String(now.getMonth()+1).padStart(2,'0')}/${now.getFullYear()}`;

let text = output
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/^- /gm, '• ')
  .replace(/---/g, '───');

text = `📋 Daily Brief — ${date}\n\n${text}\n\n───\n⏱️ Gerado em ${elapsed}s via Claude Code`;

if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n(truncado)';
}

return [{ json: { text, number: '351913095597' } }];

const today = new Date().toISOString().slice(0, 10);

const tasks7d = $('Tasks 7 Dias').all().map(i => {
  const name = i.json.property_name || 'Sem nome';
  const due = i.json.property_due_date?.start || '';
  const tags = i.json.property_tags || [];
  const prio = tags.includes('Prioridade Alta') ? '🔴' : tags.includes('Prioridade Média') ? '🟡' : '⚪';
  const overdue = due && due < today ? '⚠️ ATRASADA ' : '';
  return `${overdue}${prio} ${name} (${due})${tags.length ? ' [' + tags.join(', ') + ']' : ''}`;
}).join('\n');

const overdueCount = $('Tasks 7 Dias').all().filter(i => {
  const due = i.json.property_due_date?.start || '';
  return due && due < today;
}).length;

const inbox = $('Tasks Inbox').all().map(i => {
  const name = i.json.property_name || 'Sem nome';
  return `📥 ${name}`;
}).join('\n');
const inboxCount = $('Tasks Inbox').all().length;

const projects = $('Active Projects').all().map(i => {
  const name = i.json.property_name || i.json.Name || 'Sem nome';
  const type = i.json.property_type || '';
  const icon = type === 'Client' ? '🟢' : type === 'Prospect' ? '🟡' : '⚪';
  return `${icon} ${name}${type ? ' (' + type + ')' : ''}`;
}).join('\n');

const now = new Date();
const date = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;
const weekday = ['Domingo','Segunda','Terca','Quarta','Quinta','Sexta','Sabado'][now.getDay()];

const prompt = `Hoje e ${date}, ${weekday}. Daily Brief para Ary Ribeiro.

CONTEXTO: Consultor IA, 3 verticais: TJ (advogados BR R$2.997/mes), TM (clinicas BR R$2.997/mes), CL (imobiliarias PT E497/mes). Meta Q2: E12.857 trimestral. Revenue actual: E0. Pipeline vazio = prioridade #1 e prospeccao e conteudo.

PROJECTOS ACTIVOS (${$('Active Projects').all().length}):
${projects || '(nenhum projecto activo)'}

PROXIMOS 7 DIAS (${$('Tasks 7 Dias').all().length} tasks, ${overdueCount} atrasadas):
${tasks7d || '(nenhuma task agendada)'}

INBOX SEM DATA (${inboxCount} tasks):
${inbox || '(inbox vazio)'}

REGRAS:
1. Se revenue = E0 e pipeline vazio, ACCAO #1 e SEMPRE prospeccao ou criacao de conteudo que gere leads
2. Identificar a UNICA accao de maior impacto financeiro
3. Tasks com ATRASADA = urgente
4. Inbox >10 = flag triagem
5. Projectos sem Type=Client ou Prospect = flag sem revenue pipeline
6. Directo, zero fluff, tom de coach exigente

FORMATO:
ACCAO #1 (maior impacto financeiro - imperativa, especifica)
PIPELINE (3-5 bullets do que fazer hoje)
URGENTE (tasks atrasadas com impacto em receita)
PROJECTOS (status dos activos, flags)
INBOX (status)
LEMBRETE (1 frase sobre execucao e revenue)

Maximo 250 palavras.`;

return [{ json: { prompt, timeout: 120000 } }];
